206→// ---------------------------------------------------------------------------
207→// Auth Helpers
208→// ---------------------------------------------------------------------------
209→
210→export type TestUser = {
211→  headers: Record<string, string>;
212→};
213→
214→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
215→  const email = `test-${Date.now()}-${suffix}@test.local`;
216→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
217→    method: "POST",
218→    headers: { "Content-Type": "application/json" },
219→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
220→    redirect: "manual",
221→  });
222→
223→  if (!response.ok) {
224→    const body = await response.text();
225→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
226→  }
227→
228→  const setCookie = response.headers.getSetCookie();
229→  if (!setCookie || setCookie.length === 0) {
230→    throw new Error("Sign-up did not return session cookies");
231→  }
232→
233→  const cookieHeader = setCookie.map((c) => c.split(";")[0]).join("; ");
234→  return { headers: { Cookie: cookieHeader } };
235→}
236→
237→// ---------------------------------------------------------------------------
238→// SSE Helpers
239→// ---------------------------------------------------------------------------
240→
241→export async function collectSseEvents<T extends { type: string }>(streamUrl: string, timeoutMs: number): Promise<T[]> {
242→  const response = await fetch(streamUrl, { headers: { Accept: "text/event-stream" } });
243→  if (!response.ok || !response.body) {
244→    throw new Error(`Failed to open SSE stream (${response.status})`);
245→  }
246→
247→  const reader = response.body.getReader();
248→  const decoder = new TextDecoder();
249→  const events: T[] = [];
250→  let buffer = "";
251→
252→  const timeout = setTimeout(() => {
253→    void reader.cancel();
254→  }, timeoutMs);
255→
256→  try {
257→    while (true) {
258→      const { value, done } = await reader.read();
259→      if (done) {
260→        break;
261→      }
262→
263→      buffer += decoder.decode(value, { stream: true });
264→      const segments = buffer.split("\n\n");
265→      buffer = segments.pop() ?? "";
266→
267→      for (const segment of segments) {
268→        const dataLine = segment.split("\n").find((line) => line.startsWith("data: "));
269→        if (!dataLine) {
270→          continue;
271→        }
272→
273→        const event = JSON.parse(dataLine.slice("data: ".length)) as T;
274→        events.push(event);
275→
276→        if (event.type === "error") {
277→          const errorText = (event as { error?: string }).error;
278→          throw new Error(`SSE error event: ${errorText ?? "unknown error"}`);
279→        }
280→
281→        if (event.type === "done") {
282→          return events;
283→        }
284→      }
285→    }
286→  } finally {
287→    clearTimeout(timeout);
288→    reader.releaseLock();
289→  }
290→
291→  return events;
292→}
293→
294→// ---------------------------------------------------------------------------
295→// HTTP Helpers
296→// ---------------------------------------------------------------------------
297→
298→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
299→  const response = await fetch(url, init);
300→  if (!response.ok) {
301→    const body = await response.text();
302→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
303→  }
304→
305→  return (await response.json()) as T;
306→}
307→
308→export async function fetchRaw(url: string, init?: RequestInit): Promise<Response> {
309→  return fetch(url, init);
310→}
311→
312→// ---------------------------------------------------------------------------
313→// OAuth Helpers
314→// ---------------------------------------------------------------------------
315→
316→function base64url(buf: Buffer): string {
317→  return buf.toString("base64url");
318→}
319→
320→function generatePkce(): { verifier: string; challenge: string } {
321→  const verifier = base64url(randomBytes(32));
322→  const challenge = base64url(createHash("sha256").update(verifier).digest());
323→  return { verifier, challenge };
324→}
325→
326→/**
327→ * Obtain an OAuth2 JWT access token for MCP endpoints.
328→ * Requires a SurrealDB connection to skip consent screen.
329→ */
330→export async function getOAuthToken(
331→  baseUrl: string,
332→  surreal: Surreal,
333→  sessionHeaders: Record<string, string>,
334→  scopes: string = "graph:read graph:reason session:write offline_access",
335→): Promise<string> {
336→  // Trigger JWKS key generation if not yet done
337→  await fetch(`${baseUrl}/api/auth/jwks`);
338→
339→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
340→    method: "POST",
341→    headers: { "Content-Type": "application/json" },
342→    body: JSON.stringify({
343→      client_name: `test-client-${Date.now()}`,
344→      redirect_uris: ["http://127.0.0.1:9999/callback"],
345→      grant_types: ["authorization_code", "refresh_token"],
346→      response_types: ["code"],
347→      token_endpoint_auth_method: "none",
348→    }),
349→  });
350→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
351→
352→  const { client_id } = (await dcrRes.json()) as { client_id: string };
353→
354→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
355→    cid: client_id,
356→  });
357→
358→  const { verifier, challenge } = generatePkce();
359→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
360→  authUrl.searchParams.set("client_id", client_id);
361→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
362→  authUrl.searchParams.set("response_type", "code");
363→  authUrl.searchParams.set("scope", scopes);
364→  authUrl.searchParams.set("state", "test-state");
365→  authUrl.searchParams.set("code_challenge", challenge);
366→  authUrl.searchParams.set("code_challenge_method", "S256");
367→  authUrl.searchParams.set("resource", baseUrl);
368→
369→  const authRes = await fetch(authUrl.toString(), {
370→    headers: sessionHeaders,
371→    redirect: "manual",
372→  });
373→  if (authRes.status !== 302) throw new Error(`Authorize did not redirect: ${authRes.status}`);
374→
375→  const location = authRes.headers.get("location")!;
376→  const redirectUrl = new URL(location, baseUrl);
377→  const code = redirectUrl.searchParams.get("code") ?? "";
378→  if (!code) throw new Error(`No code in redirect: ${location}`);
379→
380→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
381→    method: "POST",
382→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
383→    body: new URLSearchParams({
384→      grant_type: "authorization_code",
385→      code,
386→      redirect_uri: "http://127.0.0.1:9999/callback",
387→      client_id,
388→      code_verifier: verifier,
389→      resource: baseUrl,
390→    }),
391→  });
392→  if (!tokenRes.ok) throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
393→
394→  const tokens = (await tokenRes.json()) as { access_token: string };
395→  return tokens.access_token;
396→}
397→
398→export type TestUserWithMcp = TestUser & {
399→  mcpHeaders: Record<string, string>;
400→};
401→
402→/**
403→ * Create a test user with both session cookie and OAuth MCP token.
404→ */
405→export async function createTestUserWithMcp(
406→  baseUrl: string,
407→  surreal: Surreal,
408→  suffix: string,
409→  scopes?: string,
410→): Promise<TestUserWithMcp> {
411→  const user = await createTestUser(baseUrl, suffix);
412→  const accessToken = await getOAuthToken(baseUrl, surreal, user.headers, scopes);
413→  return {
414→    ...user,
415→    mcpHeaders: { Authorization: `Bearer ${accessToken}` },
416→  };
417→}
418→
419→// ---------------------------------------------------------------------------
420→// Internal Utilities
421→// ---------------------------------------------------------------------------
422→
423→function requireTestEnv(name: string): string {
424→  const value = process.env[name];
425→  if (!value || value.trim().length === 0) {
426→    throw new Error(`Acceptance test requires env var ${name}`);
427→  }
428→  return value;
429→}
430→
431→async function withTimeout<T>(callback: () => Promise<T>, timeoutMs: number, label: string): Promise<T> {
432→  return await Promise.race([
433→    callback(),
434→    new Promise<T>((_, reject) => {
435→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
436→    }),
437→  ]);
438→}
