339→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
340→    method: "POST",
341→    headers: { "Content-Type": "application/json" },
342→    body: JSON.stringify({
343→      client_name: `test-client-${Date.now()}`,
344→      redirect_uris: ["http://127.0.0.1:9999/callback"],
345→      grant_types: ["authorization_code", "refresh_token"],
346→      response_types: ["code"],
347→      token_endpoint_auth_method: "none",
348→    }),
349→  });
350→  if (!dcrRes.ok) throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
351→
352→  const { client_id } = (await dcrRes.json()) as { client_id: string };
353→
354→  await surreal.query(`UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`, {
355→    cid: client_id,
