 48→  /** Extra env vars to set before the server boots (e.g. ORCHESTRATOR_MOCK_AGENT). */
 49→  env?: Record<string, string>;
 50→};
 51→
 52→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
