 55→
 56→export function setupAcceptanceSuite(
 57→  suiteName: string,
 58→  options?: AcceptanceSuiteOptions,
 59→): () => AcceptanceTestRuntime {
 60→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 61→  const namespace = `accept_${runId}`;
 62→  const suiteSlug = suiteName
 63→    .toLowerCase()
 64→    .replace(/[^a-z0-9]+/g, "_")
 65→    .replace(/^_+|_+$/g, "");
 66→  const database = `${suiteSlug || "suite"}_${Math.floor(Math.random() * 100000)}`;
 67→
 68→  let runtime: AcceptanceTestRuntime | undefined;
 69→  let server: ReturnType<typeof Bun.serve> | undefined;
 70→  let runtimeSurreal: Surreal | undefined;
 71→  let analyticsSurreal: Surreal | undefined;
 72→  let inflight: InflightTracker | undefined;
 73→  let setupSucceeded = false;
 74→
 75→  beforeAll(async () => {
 76→    // Apply env overrides before server boot
 77→    if (options?.env) {
 78→      for (const [k, v] of Object.entries(options.env)) {
 79→        process.env[k] = v;
 80→      }
 81→    }
 82→
 83→    const surreal = new Surreal();
 84→    await withTimeout(() => surreal.connect(surrealUrl), 10_000, "connect to SurrealDB");
 85→    await withTimeout(
 86→      () => surreal.signin({ username: surrealUsername, password: surrealPassword }),
 87→      10_000,
 88→      "authenticate with SurrealDB",
 89→    );
 90→
 91→    await withTimeout(() => surreal.query(`DEFINE NAMESPACE ${namespace};`), 10_000, "define test namespace");
 92→    await withTimeout(() => surreal.use({ namespace }), 10_000, "switch to test namespace");
 93→    await withTimeout(() => surreal.query(`DEFINE DATABASE ${database};`), 10_000, "define test database");
 94→    await withTimeout(
 95→      () => surreal.use({ namespace, database }),
 96→      10_000,
 97→      "switch to test namespace/database",
 98→    );
 99→
100→    const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
101→    await withTimeout(() => surreal.query(schemaSql), 20_000, "apply schema");
102→
103→    // Reserve a port so betterAuth gets the real URL at init time
104→    const tempServer = Bun.serve({ port: 0, fetch: () => new Response() });
105→    const reservedPort = tempServer.port;
106→    tempServer.stop(true);
107→    const baseUrl = `http://127.0.0.1:${reservedPort}`;
108→
109→    const config: ServerConfig = {
110→      openRouterApiKey: requireTestEnv("OPENROUTER_API_KEY"),
111→      chatAgentModelId: requireTestEnv("CHAT_AGENT_MODEL"),
112→      extractionModelId: requireTestEnv("EXTRACTION_MODEL"),
113→      pmAgentModelId: process.env.PM_AGENT_MODEL?.trim() || requireTestEnv("EXTRACTION_MODEL"),
114→      analyticsAgentModelId: requireTestEnv("ANALYTICS_MODEL"),
115→      embeddingModelId: requireTestEnv("OPENROUTER_EMBEDDING_MODEL"),
116→      embeddingDimension: Number(requireTestEnv("EMBEDDING_DIMENSION")),
117→      extractionStoreThreshold: Number(requireTestEnv("EXTRACTION_STORE_THRESHOLD")),
118→      extractionDisplayThreshold: Number(requireTestEnv("EXTRACTION_DISPLAY_THRESHOLD")),
119→      surrealUrl,
120→      surrealUsername,
121→      surrealPassword,
122→      surrealNamespace: namespace,
123→      surrealDatabase: database,
124→      port: reservedPort,
125→      betterAuthSecret: process.env.BETTER_AUTH_SECRET ?? "smoke-test-secret-at-least-32-chars-long",
126→      betterAuthUrl: baseUrl,
127→      githubClientId: process.env.GITHUB_CLIENT_ID ?? "smoke-test-github-id",
128→      githubClientSecret: process.env.GITHUB_CLIENT_SECRET ?? "smoke-test-github-secret",
129→    };
130→
131→    const deps = await createRuntimeDependencies(config);
132→    runtimeSurreal = deps.surreal;
133→    analyticsSurreal = deps.analyticsSurreal;
134→    inflight = createInflightTracker();
135→
136→    const serverDeps: ServerDependencies = {
137→      config,
138→      surreal: deps.surreal,
139→      analyticsSurreal: deps.analyticsSurreal,
140→      auth: deps.auth,
141→      chatAgentModel: deps.chatAgentModel,
142→      extractionModel: deps.extractionModel,
143→      pmAgentModel: deps.pmAgentModel,
144→      analyticsAgentModel: deps.analyticsAgentModel,
145→      embeddingModel: deps.embeddingModel,
146→      sse: createSseRegistry(),
147→      inflight,
148→    };
149→
150→    server = createBrainServer(serverDeps);
151→    const port = server.port;
152→
153→    runtime = { baseUrl, surreal, namespace, database, port };
154→    setupSucceeded = true;
155→  }, 60_000);
156→
157→  afterAll(async () => {
158→    // Drain fire-and-forget work (e.g. webhook extraction) before closing DB
159→    if (inflight) {
160→      await inflight.drain(15_000);
161→    }
162→
163→    if (server) {
164→      server.stop(true);
165→    }
166→
167→    if (runtimeSurreal) {
168→      await runtimeSurreal.close().catch(() => undefined);
169→    }
170→    if (analyticsSurreal) {
171→      await analyticsSurreal.close().catch(() => undefined);
172→    }
173→
174→    if (!runtime) {
175→      return;
176→    }
177→
178→    if (setupSucceeded && !process.env.SMOKE_KEEP_DB) {
179→      try {
180→        await withTimeout(() => runtime!.surreal.query(`REMOVE DATABASE ${database};`), 10_000, "remove test database");
181→      } catch {
182→        // Best effort cleanup.
183→      }
184→
185→      try {
186→        await withTimeout(() => runtime!.surreal.query(`REMOVE NAMESPACE ${namespace};`), 10_000, "remove test namespace");
187→      } catch {
188→        // Best effort cleanup.
189→      }
190→    }
191→
192→    await withTimeout(() => runtime!.surreal.close(), 2_000, "close SurrealDB").catch(() => undefined);
193→  }, 20_000);
194→
195→  return () => {
196→    if (!runtime) {
197→      throw new Error("Acceptance runtime requested before suite setup completed");
198→    }
199→    return runtime;
200→  };
201→}
