214→export async function createTestUser(baseUrl: string, suffix: string): Promise<TestUser> {
215→  const email = `test-${Date.now()}-${suffix}@test.local`;
216→  const response = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
217→    method: "POST",
218→    headers: { "Content-Type": "application/json" },
219→    body: JSON.stringify({ name: "Test User", email, password: "test-password-123" }),
220→    redirect: "manual",
221→  });
222→
223→  if (!response.ok) {
224→    const body = await response.text();
225→    throw new Error(`Failed to create test user (${response.status}): ${body}`);
226→  }
227→
228→  const setCookie = response.headers.getSetCookie();
229→  if (!setCookie || setCookie.length === 0) {
230→    throw new Error("Sign-up did not return session cookies");
