405→export async function createTestUserWithMcp(
406→  baseUrl: string,
407→  surreal: Surreal,
408→  suffix: string,
409→  scopes?: string,
410→): Promise<TestUserWithMcp> {
411→  const user = await createTestUser(baseUrl, suffix);
412→  const accessToken = await getOAuthToken(baseUrl, surreal, user.headers, scopes);
413→  return {
414→    ...user,
415→    mcpHeaders: { Authorization: `Bearer ${accessToken}` },
