116→  const requesterRecord = new RecordId("identity", requesterId);
117→
118→  const content: Record<string, unknown> = {
119→    goal: opts.goal,
120→    reasoning: opts.reasoning,
121→    status: "draft",
122→    priority: opts.priority ?? 50,
123→    action_spec: opts.action_spec,
124→    trace_id: `trace-${intentId}`,
125→    requester: requesterRecord,
126→    workspace: workspaceRecord,
127→    created_at: new Date(),
128→  };
129→
130→  if (opts.budget_limit) {
131→    content.budget_limit = opts.budget_limit;
132→  }
133→
134→  await surreal.query(`CREATE $intent CONTENT $content;`, {
135→    intent: intentRecord,
136→    content,
137→  });
138→
139→  // Link to originating task if provided
140→  if (opts.taskId) {
141→    const taskRecord = new RecordId("task", opts.taskId);
142→    await surreal.query(
143→      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
144→      { intent: intentRecord, task: taskRecord },
145→    );
146→  }
147→
148→  return { intentId, intentRecord };
149→}
