437→/**
438→ * Wires the SurrealQL EVENT that fires when an intent transitions to
439→ * pending_auth. The EVENT calls http::post to the real test server's
440→ * evaluate endpoint, enabling true E2E testing of the async evaluation flow.
441→ *
442→ * Callback host can be overridden via INTENT_EVAL_CALLBACK_HOST.
443→ * Call this in beforeAll after the test server has booted.
444→ */
445→export async function wireIntentEvaluationEvent(
446→  surreal: Surreal,
447→  port: number,
448→): Promise<void> {
449→  const configuredHost = process.env.INTENT_EVAL_CALLBACK_HOST?.trim();
450→  const candidateHosts = configuredHost && configuredHost.length > 0
451→    ? [configuredHost]
452→    : ["127.0.0.1", "host.docker.internal"];
453→
454→  let baseUrl: string | undefined;
455→  let lastError = "";
456→
457→  for (const host of candidateHosts) {
458→    const candidateBaseUrl = `http://${host}:${port}`;
459→
460→    try {
461→      await surreal.query(`RETURN http::head($url);`, {
462→        url: `${candidateBaseUrl}/healthz`,
463→      });
464→      baseUrl = candidateBaseUrl;
465→      break;
466→    } catch (error) {
467→      lastError = error instanceof Error ? error.message : String(error);
468→    }
469→  }
470→
471→  if (!baseUrl) {
472→    throw new Error(
473→      `Unable to reach acceptance server from SurrealDB for intent callback. ` +
474→      `Tried hosts: ${candidateHosts.join(", ")} on port ${port}. ` +
475→      `Last error: ${lastError}`,
476→    );
477→  }
478→
479→  await surreal.query(`
480→    DEFINE EVENT OVERWRITE intent_pending_auth ON intent
481→      ASYNC
482→      RETRY 3
483→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
484→      THEN {
485→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
486→      };
487→  `);
488→}
